const body = $json.body ?? $json;
const messageText = body?.entry?.[0]?.changes?.[0]?.value?.messages?.[0]?.text?.body ?? body?.text ?? body?.message ?? '';
const runId = body?.run_id ?? body?.runId ?? `run_${Date.now()}_${Math.random().toString(36).slice(2, 10)}`;
const jiraIssueKey = String(body?.jira_issue_key ?? body?.issue_key ?? '').trim();
const jiraBaseUrl = String(body?.jira_base_url ?? body?.jira?.base_url ?? '').trim();
const jiraEmail = String(body?.jira_email ?? body?.jira?.email ?? '').trim();
const jiraApiToken = String(body?.jira_api_token ?? body?.jira?.api_token ?? '').trim();
const multiagentApiKey = String(body?.multiagent_api_key ?? body?.api_key ?? '').trim();

function inferIntent(text) {
  const t = String(text || '').toLowerCase();
  if (!t) {
    return { name: 'unknown', confidence: 0.0, entities: [], reasoning: 'empty_input' };
  }

  const rules = [
    { name: 'generate_backend', confidence: 0.92, terms: ['backend', 'api', 'endpoint', 'controller', 'service'] },
    { name: 'deploy_backend', confidence: 0.9, terms: ['deploy', 'desplegar', 'release', 'produccion'] },
    { name: 'review_backend', confidence: 0.88, terms: ['review', 'revisar', 'auditar', 'quality', 'qa'] },
    { name: 'planner_help', confidence: 0.8, terms: ['plan', 'planning', 'roadmap', 'organiza'] }
  ];

  for (const rule of rules) {
    if (rule.terms.some((term) => t.includes(term))) {
      return {
        name: rule.name,
        confidence: rule.confidence,
        entities: [{ key: 'matched_terms', value: rule.terms.filter((term) => t.includes(term)) }],
        reasoning: 'keyword_match'
      };
    }
  }

  return { name: 'freeform_request', confidence: 0.65, entities: [], reasoning: 'fallback' };
}

const explicitIntent = body?.intent;
const intent = (explicitIntent && typeof explicitIntent === 'object')
  ? {
      name: String(explicitIntent.name ?? 'unknown'),
      confidence: Number(explicitIntent.confidence ?? 0),
      entities: Array.isArray(explicitIntent.entities) ? explicitIntent.entities : [],
      reasoning: String(explicitIntent.reasoning ?? 'provided')
    }
  : inferIntent(messageText);

const structuredTask = `[${intent.name}] ${messageText || 'No task provided'}`;

return [{
  json: {
    run_id: runId,
    task: structuredTask,
    source: 'whatsapp',
    intent,
    multiagent_api_key: multiagentApiKey,
    jira_issue_key: jiraIssueKey,
    jira_base_url: jiraBaseUrl,
    jira_email: jiraEmail,
    jira_api_token: jiraApiToken,
    raw: body
  }
}];

const deploymentRaw = $json.deployment;
let deployment = {};
if (typeof deploymentRaw === 'string') {
  try {
    deployment = JSON.parse(deploymentRaw);
  } catch (e) {
    deployment = { error: 'Failed to parse deployment JSON' };
  }
} else if (typeof deploymentRaw === 'object') {
  deployment = deploymentRaw;
}
const deploymentUrl = deployment.deployment_url || deployment.service_url || deployment.url || deployment.deploy_url || null;
const gitHubRepo = deployment.github_repo?.repo_url || deployment.repo_url || null;
const taskStatus = ($json.status || 'validated') === 'deployed' ? 'done' : (($json.status || 'validated') === 'validated' ? 'done' : String($json.status || 'in_progress'));
return [{
  json: {
    run_id: $json.run_id,
    status: 'approved',
    summary: ($json.status === 'deployed') ? 'App successfully deployed to Render' : 'Pipeline executed successfully',
    intent: $('Normalize Input').first().json.intent,
    deployment,
    deploymentStatus: $json.status,
    whatsapp_response: {
      channel: 'meta_cloud_api',
      task_status: taskStatus,
      deployment_url: deploymentUrl,
      github_repo: gitHubRepo,
      error_message: null
    }
  }
}];

const review = $json.review || {};
const findings = Array.isArray(review.findings) ? review.findings : [];
const errorMessage = findings.length ? findings.join(' | ') : 'Reviewer did not approve the generated output';
return [{
  json: {
    run_id: $json.run_id,
    status: 'changes_required',
    summary: 'Reviewer did not approve the generated output',
    intent: $('Normalize Input').first().json.intent,
    review,
    approved: $json.approved,
    whatsapp_response: {
      channel: 'meta_cloud_api',
      task_status: 'changes_required',
      pr_url: null,
      deploy_url: null,
      error_message: errorMessage
    }
  }
}];
